const incoming = $input.item.json.body || $input.item.json;
const headers = $input.item.json.headers || {};

function toTitleCase(s) {
  return (s || '').toString().trim().replace(/\s+/g, ' ').toLowerCase().replace(/(^|\s|-)([a-z])/g, function(_, p, c) { return p + c.toUpperCase(); });
}
function cleanEmail(e) {
  return (e || '').toString().trim().toLowerCase().replace(/@@+/g, '@').replace(/gmail\.con$/, 'gmail.com');
}
function cleanPhone(p) {
  const d = (p || '').toString().replace(/\D/g, '');
  if (d.length === 10) return '+1 (' + d.slice(0,3) + ') ' + d.slice(3,6) + '-' + d.slice(6);
  if (d.length === 11 && d.charAt(0) === '1') return '+1 (' + d.slice(1,4) + ') ' + d.slice(4,7) + '-' + d.slice(7);
  return p || '';
}
function stripJunk(s) { return (s || '').toString().trim().replace(/\s+/g, ' '); }

const result = {
  name: toTitleCase(incoming.name),
  business: stripJunk(incoming.business),
  email: cleanEmail(incoming.email),
  phone: cleanPhone(incoming.phone),
  message: stripJunk(incoming.message),
  source: incoming.source || 'flowlayerai.com',
  submitted_at: incoming.submitted_at || new Date().toISOString(),
  user_agent: headers['user-agent'] || null,
  referer: headers.referer || null
};

return { json: result };

const lead = $('Fuzzy Logic & Clean Data').item.json;
const raw = $input.item.json.message && $input.item.json.message.content ? $input.item.json.message.content : ($input.item.json.content || $input.item.json);
let ai = raw;
if (typeof raw === 'string') {
  try { ai = JSON.parse(raw); } catch (e) { ai = {}; }
}
const score = parseInt(ai.lead_score, 10);
const merged = Object.assign({}, lead, {
  industry_category: ai.industry_category || 'Unknown',
  automation_pain_point: ai.automation_pain_point || 'Other / Unclear',
  pain_point_reason: ai.pain_point_reason || '',
  urgency: ai.urgency || 'MEDIUM',
  urgency_reason: ai.urgency_reason || '',
  lead_score: Number.isFinite(score) ? score : 50,
  summary: ai.summary || '',
  suggested_next_action: ai.suggested_next_action || ''
});
return { json: merged };
